#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* createNode(int value) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->value = value;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to calculate the maximum amount of money that can be robbed
int* calculateMaxRob(Node* root) {
    if (root == NULL) {
        int* result = (int*) malloc(2 * sizeof(int));
        result[0] = 0;
        result[1] = 0;
        return result;
    }

    int* leftResult = calculateMaxRob(root->left);
    int* rightResult = calculateMaxRob(root->right);

    int* result = (int*) malloc(2 * sizeof(int));
    result[0] = root->value + leftResult[1] + rightResult[1];
    result[1] = (leftResult[0] > leftResult[1] ? leftResult[0] : leftResult[1]) + (rightResult[0] > rightResult[1] ? rightResult[0] : rightResult[1]);

    free(leftResult);
    free(rightResult);

    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        Node* root = NULL;
        // Read the tree nodes and construct the tree
        for (int i = 0; i < n; i++) {
            int value;
            scanf("%d", &value);
            Node* newNode = createNode(value);
            if (root == NULL) {
                root = newNode;
            } else {
                // Add the new node to the tree
                Node* current = root;
                Node* parent = NULL;
                while (current != NULL) {
                    parent = current;
                    if (i % 2 == 1) {
                        current = current->left;
                    } else {
                        current = current->right;
                    }
                }
                if (i % 2 == 1) {
                    parent->left = newNode;
                } else {
                    parent->right = newNode;
                }
            }
        }
        // Calculate and print the maximum amount of money that can be robbed
        int* result = calculateMaxRob(root);
        printf("%d\n", result[0] > result[1] ? result[0] : result[1]);
        free(result);
    }
    return 0;
}

