        this.value = value;
        this.left = null;
        this.right = null;
    }
}

public class Main {
    // Function to calculate the maximum amount of money that can be robbed
    public static int[] calculateMaxRob(Node root) {
        if (root == null) {
            int[] result = new int[2];
            result[0] = 0;
            result[1] = 0;
            return result;
        }

        int[] leftResult = calculateMaxRob(root.left);
        int[] rightResult = calculateMaxRob(root.right);

        int[] result = new int[2];
        result[0] = root.value + leftResult[1] + rightResult[1];
        result[1] = (leftResult[0] > leftResult[1] ? leftResult[0] : leftResult[1]) + (rightResult[0] > rightResult[1] ? rightResult[0] : rightResult[1]);

        return result;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            Node root = null;
            // Read the tree nodes and construct the tree
            for (int i = 0; i < n; i++) {
                int value = scanner.nextInt();
                Node newNode = new Node(value);
                if (root == null) {
                    root = newNode;
                } else {
                    // Add the new node to the tree
                    Node current = root;
                    Node parent = null;
                    while (current != null) {
                        parent = current;
                        if (i % 2 == 1) {
                            current = current.left;
                        } else {
                            current = current.right;
                        }
                    }
                    if (i % 2 == 1) {
                        parent.left = newNode;
                    } else {
                        parent.right = newNode;
                    }
                }
            }
            // Calculate and print the maximum amount of money that can be robbed
            int[] result = calculateMaxRob(root);
            System.out.println(result[0] > result[1] ? result[0] : result[1]);
        }
    }
}

