    constructor(value) {
        this.value = value;
        this.left = null;
        this.right = null;
    }
}

// Function to calculate the maximum amount of money that can be robbed
function calculateMaxRob(root) {
    if (root === null) {
        return [0, 0];
    }

    let leftResult = calculateMaxRob(root.left);
    let rightResult = calculateMaxRob(root.right);

    let result = [0, 0];
    result[0] = root.value + leftResult[1] + rightResult[1];
    result[1] = Math.max(leftResult[0], leftResult[1]) + Math.max(rightResult[0], rightResult[1]);

    return result;
}

// Read the number of test cases
let T = parseInt(input[idx++]);
while (T-- > 0) {
    // Read the number of nodes in the tree
    let n = parseInt(input[idx++]);
