    // Read the tree nodes and construct the tree
    let nodes = input[idx++].split(' ').map(Number);
    let queue = [];
    if (n > 0) {
        root = new Node(nodes[0]);
        queue.push(root);
    }
    let i = 1;
    while (i < n && queue.length > 0) {
        let current = queue.shift();
        if (i < n) {
            current.left = new Node(nodes[i]);
            queue.push(current.left);
            i++;
